const Q_CASE: QuizQuestion[] = [
  { id: "case-001", type: "case", question: "该患者最可能的诊断是？", case: "55 岁男性，会计，长期伏案工作。右肩外展、上举时疼痛 2 个月，夜间痛醒。查体：Jobe 试验阳性，Neer 试验阳性，疼痛弧 60°-120°。X 线未见骨折。", options: { A: "冻结肩", B: "肩峰下撞击综合征/冈上肌腱炎", C: "肩袖全层撕裂", D: "颈椎病" }, answer: "B", explanation: "Jobe+Neer+疼痛弧+夜间痛提示肩峰下撞击/冈上肌腱炎；肩袖全层撕裂常伴明显肌力下降。", category: "case", subCategory: "案例-肩痛", difficulty: "medium", source: "《肩关节外科》", tags: ["肩峰下撞击"] },
  { id: "case-002", type: "case", question: "首选治疗方案是？", case: "30 岁女性，办公室职员。腰痛 1 周，无下肢放射痛，咳嗽不加重。VAS 4/10。直腿抬高试验阴性。", options: { A: "立即手术", B: "绝对卧床 2 周", C: "健康教育+姿势矫正+核心训练", D: "长期口服阿片类" }, answer: "C", explanation: "无神经根受压的非特异性腰痛首选教育、运动、姿势矫正。", category: "case", subCategory: "案例-腰痛", difficulty: "easy", source: "《Lancet 2018》", tags: ["腰痛"], evidenceLevel: "A" },
  { id: "case-003", type: "case", question: "该患者需紧急转诊的指征是？", case: "65 岁女性，突发腰痛 3 天，伴右小腿放射痛，VAS 8/10。查体：右足背伸肌力 2 级，鞍区感觉减退，大便 2 日未解。", options: { A: "门诊理疗", B: "观察 1 周", C: "立即转诊骨科（疑似马尾综合征）", D: "加大镇痛药" }, answer: "C", explanation: "鞍区感觉+大小便障碍+肌力下降提示马尾综合征，需紧急手术。", category: "case", subCategory: "案例-红旗", difficulty: "hard", source: "《骨科外科》", tags: ["马尾综合征"] },
  { id: "case-004", type: "case", question: "该患者最可能的诊断是？", case: "70 岁男性，突发左膝肿痛 6 小时，夜间痛醒。查体：左膝红、肿、热，浮髌试验阳性，体温 38.5℃。", options: { A: "KOA 急性发作", B: "化脓性关节炎（红旗征）", C: "痛风急性发作", D: "半月板损伤" }, answer: "B", explanation: "老年男性 + 急性单关节肿热 + 发热需首先排查化脓性关节炎。", category: "case", subCategory: "案例-红旗", difficulty: "hard", source: "《骨科感染》", tags: ["化脓性关节炎"] },
  { id: "case-005", type: "case", question: "康复治疗的首要目标是？", case: "62 岁男性，心肌梗死 PCI 术后 2 周，生命体征平稳。", options: { A: "立即高强度间歇训练", B: "低强度床上活动+呼吸训练+监测生命体征", C: "完全卧床 1 月", D: "出院后再说" }, answer: "B", explanation: "心梗后早期应低强度活动+呼吸训练+监测，符合 AVERT 原则。", category: "case", subCategory: "案例-心肺", difficulty: "medium", source: "《心肺康复》", tags: ["心梗后"], evidenceLevel: "A" },
  { id: "case-006", type: "case", question: "Brunnstrom 分期最可能是？", case: "58 岁男性，脑梗死后 4 周。右上肢 Brunnstrom Ⅱ 期表现——开始出现联合反应。", options: { A: "Ⅰ期弛缓", B: "Ⅱ期联合反应", C: "Ⅲ期痉挛达峰", D: "Ⅵ期接近正常" }, answer: "B", explanation: "联合反应是 Brunnstrom Ⅱ 期的特征。", category: "case", subCategory: "案例-神经", difficulty: "medium", source: "《神经康复学》", tags: ["Brunnstrom"] },
  { id: "case-007", type: "case", question: "该患者最可能的诊断是？", case: "45 岁女性，长跑爱好者。右足跟痛 1 月，晨起第一步最痛，行走后缓解。X 线示跟骨骨刺。", options: { A: "跟腱断裂", B: "足底筋膜炎", C: "应力性骨折", D: "踝管综合征" }, answer: "B", explanation: "晨起第一步痛是足底筋膜炎典型表现。", category: "case", subCategory: "案例-足踝", difficulty: "easy", source: "《足踝外科》", tags: ["足底筋膜炎"] },
  { id: "case-008", type: "case", question: "首选康复治疗是？", case: "25 岁男性，足球运动员。右膝扭伤 1 天，关节肿胀，Lachman 试验阳性，前抽屉试验阳性。", options: { A: "ACL 重建术前康复：消肿+ROM+肌力", B: "立即跑跳", C: "长期绝对固定", D: "不需处理" }, answer: "A", explanation: "ACL 损伤术前康复（prehab）可改善术后效果。", category: "case", subCategory: "案例-ACL", difficulty: "medium", source: "《运动医学》", tags: ["ACL"] },
  { id: "case-009", type: "case", question: "该患者首要检查是？", case: "28 岁孕妇，孕 30 周，腰骶部疼痛 2 周，伴大腿内侧放射。骨盆挤压试验阳性。", options: { A: "立即 X 线", B: "立即 CT", C: "临床诊断 PGP（骨盆带疼痛）+ 物理治疗", D: "抗生素治疗" }, answer: "C", explanation: "妊娠期 PGP 首选保守治疗，避免 X 线/CT 辐射。", category: "case", subCategory: "案例-产康", difficulty: "medium", source: "《妇产科学》", tags: ["PGP"] },
  { id: "case-010", type: "case", question: "该患者最可能的诊断是？", case: "8 岁脑瘫儿童，粗大运动受限明显，可在辅具辅助下短距离行走，5 岁后才能独坐稳。", options: { A: "GMFCS Ⅰ级", B: "GMFCS Ⅱ级", C: "GMFCS Ⅲ级", D: "GMFCS Ⅴ级" }, answer: "C", explanation: "需辅具短距离行走 + 5 岁后独坐，符合 GMFCS Ⅲ 级。", category: "case", subCategory: "案例-儿童", difficulty: "hard", source: "《儿童康复学》", tags: ["GMFCS"] },
  { id: "case-011", type: "case", question: "该患者最可能受累的肌群是？", case: "50 岁女性，洗衣后突发右肩疼痛，活动受限。查体：右肩外展 60°-120° 疼痛，Jobe（+）。", options: { A: "三角肌", B: "冈上肌", C: "斜方肌", D: "胸大肌" }, answer: "B", explanation: "Jobe 试验阳性+疼痛弧提示冈上肌病变。", category: "case", subCategory: "案例-肩痛", difficulty: "easy", source: "《骨科特殊检查》", tags: ["冈上肌"] },
  { id: "case-012", type: "case", question: "下一步最佳处理是？", case: "72 岁女性，跌倒后右髋疼痛不能行走。右下肢短缩、外旋。", options: { A: "卧床休息", B: "立即拍 X 线排查髋部骨折", C: "立即推拿", D: "针灸" }, answer: "B", explanation: "跌倒+短缩外旋典型股骨颈/转子间骨折，需立即 X 线。", category: "case", subCategory: "案例-红旗", difficulty: "easy", source: "《骨科创伤》", tags: ["髋部骨折"] },
  { id: "case-013", type: "case", question: "该患者最可能的诊断是？", case: "35 岁女性，长期伏案+电脑。右手拇、示、中指麻木 3 月，夜间麻醒，甩手缓解，Phalen（+）。", options: { A: "颈椎病", B: "腕管综合征", C: "肘管综合征", D: "胸廓出口综合征" }, answer: "B", explanation: "正中神经 3 指半麻木+夜间麻醒+Phalen 阳性典型腕管综合征。", category: "case", subCategory: "案例-手外", difficulty: "easy", source: "《手外科学》", tags: ["腕管"] },
  { id: "case-014", type: "case", question: "该患者最佳干预方案是？", case: "65 岁女性，KOA 5 年，X 线 K-L Ⅲ 级，BMI 28，股四头肌萎缩。", options: { A: "立即 TKA", B: "减重+股四头肌强化+NSAIDs+辅具", C: "完全卧床", D: "不做处理" }, answer: "B", explanation: "K-L Ⅲ 级未达 TKA 指征，保守治疗+减重+肌力训练是首选。", category: "case", subCategory: "案例-KOA", difficulty: "medium", source: "AAOS", tags: ["KOA"] },
  { id: "case-015", type: "case", question: "最可能的诊断是？", case: "20 岁篮球运动员，落地时右膝扭伤，\"砰\" 声，10 分钟后明显肿胀，活动受限。", options: { A: "内侧副韧带损伤", B: "ACL 断裂", C: "半月板边缘撕裂", D: "髌骨脱位" }, answer: "B", explanation: "非接触性减速+响声+快速血肿是 ACL 断裂典型表现。", category: "case", subCategory: "案例-ACL", difficulty: "medium", source: "《运动医学》", tags: ["ACL"] },
  { id: "case-016", type: "case", question: "下一步最佳处理是？", case: "40 岁男性，建筑工人。突感腰部\"撕裂\"样剧痛，放射至左小腿，左足背伸肌力下降。SLR 40° 阳性。", options: { A: "卧床休息 2 周", B: "腰围+保守治疗+观察神经功能", C: "立即手术", D: "不予处理" }, answer: "B", explanation: "椎间盘突出伴肌力下降需密切观察，多数可保守治疗，肌力进行性下降则手术。", category: "case", subCategory: "案例-椎间盘", difficulty: "hard", source: "《脊柱外科》", tags: ["椎间盘突出"] },
  { id: "case-017", type: "case", question: "该患者最可能的诊断是？", case: "55 岁女性，右手桡侧 3 指麻木 1 年，Tinel 征（腕部）阳性，肌电图示正中神经腕部传导减慢。", options: { A: "颈椎病", B: "腕管综合征", C: "肘管综合征", D: "胸廓出口综合征" }, answer: "B", explanation: "Tinel+肌电图正中神经腕部传导减慢确诊腕管综合征。", category: "case", subCategory: "案例-手外", difficulty: "medium", source: "《手外科学》", tags: ["腕管"] },
  { id: "case-018", type: "case", question: "该患者最可能的诊断是？", case: "45 岁男性，突发胸背撕裂样剧痛，向腹部放射，血压 80/50 mmHg。", options: { A: "心绞痛", B: "主动脉夹层", C: "胆绞痛", D: "肾绞痛" }, answer: "B", explanation: "胸背撕裂痛+低血压是主动脉夹层典型表现，立即 CT 血管成像。", category: "case", subCategory: "案例-红旗", difficulty: "hard", source: "《血管外科学》", tags: ["主动脉夹层"] },
  { id: "case-019", type: "case", question: "首选康复治疗是？", case: "30 岁女性，办公室职员。颈肩僵硬伴头痛 3 月，颈活动受限，斜方肌上束压痛。", options: { A: "手术", B: "颈深屈肌强化+姿势矫正+手法", C: "立即颈椎牵引", D: "不处理" }, answer: "B", explanation: "颈肌筋膜炎保守治疗：颈深屈肌强化、姿势矫正、手法治疗。", category: "case", subCategory: "案例-颈痛", difficulty: "medium", source: "《骨科康复学》", tags: ["颈肌筋膜炎"] },
  { id: "case-020", type: "case", question: "该患者最可能的诊断是？", case: "25 岁女性，产后 1 月，耻骨联合处剧痛，步行困难，骨盆挤压试验阳性。", options: { A: "尾骨痛", B: "产后骨盆带疼痛 PGP", C: "腰椎间盘突出", D: "骶髂关节炎" }, answer: "B", explanation: "产后+耻骨联合痛+骨盆挤压阳性=产后 PGP。", category: "case", subCategory: "案例-产康", difficulty: "medium", source: "《妇产科学》", tags: ["PGP"] },
  { id: "case-021", type: "case", question: "该患者首选处理是？", case: "12 岁男孩，运动后膝前痛，胫骨结节处压痛，X 线示胫骨结节骨骺碎裂。", options: { A: "手术", B: "减少运动+冰敷+股四头肌拉伸", C: "石膏固定 6 周", D: "不处理" }, answer: "B", explanation: "Osgood-Schlatter 病首选减少运动+股四头肌拉伸+冰敷，预后良好。", category: "case", subCategory: "案例-儿童", difficulty: "medium", source: "《小儿骨科》", tags: ["Osgood"] },
  { id: "case-022", type: "case", question: "该患者最可能的诊断是？", case: "70 岁女性，渐进性手部精细动作障碍 2 年，静止性震颤，动作迟缓，\"小字征\"。", options: { A: "脑卒中", B: "帕金森病", C: "小脑萎缩", D: "周围神经病" }, answer: "B", explanation: "静止性震颤+动作迟缓+小字征是帕金森三主征。", category: "case", subCategory: "案例-神经", difficulty: "easy", source: "《神经病学》", tags: ["帕金森"] },
  { id: "case-023", type: "case", question: "该患者最佳治疗策略是？", case: "60 岁男性，COPD 稳定期，6MWT 320 米，mMRC 3 级。", options: { A: "完全卧床", B: "运动训练+呼吸训练+教育", C: "不需处理", D: "高压氧" }, answer: "B", explanation: "COPD 稳定期肺康复（运动+呼吸+教育）一线治疗。", category: "case", subCategory: "案例-心肺", difficulty: "medium", source: "《心肺康复》", tags: ["COPD"], evidenceLevel: "A" },
  { id: "case-024", type: "case", question: "该患者最可能的诊断是？", case: "40 岁男性，程序员。右手腕夜间麻醒 3 月，甩手缓解，Tinel（腕部）阳性，Phalen 阳性。", options: { A: "颈椎病", B: "腕管综合征", C: "肘管综合征", D: "胸廓出口综合征" }, answer: "B", explanation: "腕管综合征典型表现。", category: "case", subCategory: "案例-手外", difficulty: "easy", source: "《手外科学》", tags: ["腕管"] },
  { id: "case-025", type: "case", question: "该患者最佳处理是？", case: "65 岁男性，膝关节置换术后 3 周，屈曲 80°，伸直差 10°，股四头肌激活不良。", options: { A: "手术翻修", B: "强化股四头肌+被动伸直训练+屈曲练习", C: "完全不训练", D: "出院" }, answer: "B", explanation: "TKA 术后 3 周典型康复：股四头肌激活、伸直训练、屈曲练习。", category: "case", subCategory: "案例-TKA", difficulty: "medium", source: "《关节外科康复》", tags: ["TKA"] },
  { id: "case-026", type: "case", question: "该患者最可能的诊断是？", case: "30 岁男性，跑者。右足跟底部疼痛，晨起第一步痛明显，行走后略缓解。", options: { A: "跟腱断裂", B: "足底筋膜炎", C: "胫骨骨膜炎", D: "应力性骨折" }, answer: "B", explanation: "晨起第一步痛是足底筋膜炎典型。", category: "case", subCategory: "案例-足踝", difficulty: "easy", source: "《足踝外科》", tags: ["足底筋膜炎"] },
  { id: "case-027", type: "case", question: "该患者首要红旗征筛查是？", case: "50 岁女性，颈肩痛 1 年，加重 1 周。伴行走不稳、双手麻木。", options: { A: "MRI 排查脊髓型颈椎病", B: "门诊理疗", C: "不处理", D: "推拿" }, answer: "A", explanation: "行走不稳+双手麻木提示脊髓型颈椎病，需 MRI 评估。", category: "case", subCategory: "案例-颈痛", difficulty: "hard", source: "《脊柱外科》", tags: ["脊髓型颈椎病"] },
  { id: "case-028", type: "case", question: "该患者最可能的诊断是？", case: "60 岁男性，突发左小腿剧烈疼痛、肿胀，腓肠肌压痛明显，Homans 征阳性。", options: { A: "腓肠肌拉伤", B: "下肢深静脉血栓（DVT）", C: "跟腱断裂", D: "Baker 囊肿破裂" }, answer: "B", explanation: "Homans+小腿肿胀疼痛=DVT 需紧急排查（避免肺栓塞）。", category: "case", subCategory: "案例-红旗", difficulty: "hard", source: "《血管外科学》", tags: ["DVT"] },
  { id: "case-029", type: "case", question: "该患者最佳康复治疗是？", case: "30 岁产后女性，盆底肌力减弱，尿失禁 3 月。", options: { A: "盆底肌训练 Kegel 练习", B: "绝对卧床", C: "抗生素", D: "不处理" }, answer: "A", explanation: "产后压力性尿失禁首选 Kegel 训练。", category: "case", subCategory: "案例-产康", difficulty: "easy", source: "《妇产科学》", tags: ["盆底"] },
  { id: "case-030", type: "case", question: "该患者最可能的诊断是？", case: "6 岁儿童，跑步时常跌倒，蹲位呈阳性 Gowers 征，腓肠肌假性肥大。", options: { A: "脑瘫", B: "Duchenne 肌营养不良", C: "脊髓性肌萎缩", D: "先天性肌病" }, answer: "B", explanation: "Gowers 征+腓肠肌假性肥大是 DMD 经典表现。", category: "case", subCategory: "案例-儿童", difficulty: "hard", source: "《儿童康复学》", tags: ["DMD"] },
  { id: "case-031", type: "case", question: "该患者最可能的诊断是？", case: "55 岁女性，右手示指、中指屈曲时弹响，掌指关节掌侧可触及结节。", options: { A: "腱鞘囊肿", B: "扳机指（狭窄性腱鞘炎）", C: "类风湿", D: "腱鞘炎" }, answer: "B", explanation: "屈指弹响+掌侧结节=扳机指。", category: "case", subCategory: "案例-手外", difficulty: "easy", source: "《手外科学》", tags: ["扳机指"] },
  { id: "case-032", type: "case", question: "该患者下一步最佳处理是？", case: "28 岁男性，举重后右肩疼痛，\"pop\" 声，外旋抗阻无力。", options: { A: "X 线+MRI 排查肩袖损伤", B: "立即推拿", C: "不处理", D: "长期绝对固定" }, answer: "A", explanation: "举重+pop+外旋无力需排除肩袖损伤，MRI 评估。", category: "case", subCategory: "案例-肩痛", difficulty: "medium", source: "《肩关节外科》", tags: ["肩袖"] },
  { id: "case-033", type: "case", question: "该患者最佳治疗策略是？", case: "70 岁女性，KOA 10 年，X 线 K-L Ⅳ 级，疼痛 VAS 8/10，保守治疗 6 月无效。", options: { A: "继续保守治疗", B: "TKA 评估", C: "关节融合", D: "截肢" }, answer: "B", explanation: "K-L Ⅳ + 保守无效 + 严重疼痛是 TKA 适应证。", category: "case", subCategory: "案例-KOA", difficulty: "hard", source: "《膝关节外科》", tags: ["TKA"] },
];

